<?phpclass Translate{	// Set active translation by language abbreviation. If $language is missling, load default translation		function set($language = false)	{		global $settings;				if ($language)			$_SESSION['translation'] = MySQL::get("SELECT * FROM `languages` WHERE `abbr` = '".$language."'");		if (!$_SESSION['translation'])			$_SESSION['translation'] = MySQL::get("SELECT * FROM `languages` WHERE `id` = '".($settings->default_language)."'");				return $_SESSION['translation'];	}		function set_by_id($id)	{		if (!$id)			return false;			$_SESSION['translation'] = MySQL::get("SELECT * FROM `languages` WHERE `id` = ".$id);				return $_SESSION['translation'];	}		// Get language by id. If $id is missing get all languages		function get($id = false)	{		if ($id)			return MySQL::get("SELECT * FROM `languages` WHERE `id` = '".$id."'");		else			return MySQL::table("SELECT * FROM `languages`");	}}?>